@{              
            var headerReqtOutput = string.Join("
", context?.Request?.Headers?.Select(h => $"{h.Key}: {string.Join(";", h.Value)}"));
            var ReqtBody = context?.Request?.Body?.As(preserveContent: true) ?? "No Body";
            return $"

Request Headers:
{headerReqtOutput}

Request Body:
{ReqtBody}

";
        }

@{              
            var headerRespOutput = string.Join("
", context?.Response?.Headers?.Select(h => $"{h.Key}: {string.Join(";", h.Value)}"));
            var RespBody = context?.Response?.Body?.As(preserveContent: true) ?? "No Body";
            return $"

Response Headers:
{headerRespOutput}

Response Body:
{RespBody}

";
        }
